import React from "react";
import classes from './Footer.module.css';


const Footer = () => {
    return <footer className={classes.footer}>
        <div>
            <ul className={classes.footer_contacts}>
                <li className={classes.footer_contacts}><a href="mailto:viktorovich85@inbox.ru"
                                                                    className={classes.footer_contacts}>viktorovich85@inbox.ru</a>
                </li>
                <li className={classes.footer_contacts}><a className={classes.footer_contacts} href="tel:+7 (927) 110-1106">+7 (927) 110-1106</a>
                </li>
            </ul>
            <p className={classes.footer_any_questions}>Если у вас есть вопросы или предложения, свяжитесь с мной любым удобным
                способом.
            </p>
            <div className={classes.footer_copyright}>© 2020 Vitaliy Shiryaev</div>

        </div>
    </footer>
}

export default Footer;

